function initLightbox(){const box=document.createElement("div");box.className="lightbox";box.innerHTML='<img alt="Certificate enlarged view">';document.body.appendChild(box);const img=box.querySelector("img");document.querySelectorAll("[data-lightbox]").forEach(link=>link.addEventListener("click",e=>{e.preventDefault();img.src=link.getAttribute("href");box.classList.add("open")}));box.addEventListener("click",()=>box.classList.remove("open"))}
